head.script:
//
/* Force viewport: prevent auto-zoom on refresh */
if(document.querySelector&&document.querySelector('meta[name="viewport"]')){
  document.querySelector('meta[name="viewport"]').setAttribute('content','width=device-width,initial-scale=1.0,maximum-scale=1.0,user-scalable=0,viewport-fit=cover');
}
/* Prevent pinch-zoom on iOS Safari */
document.addEventListener('gesturestart',function(e){e.preventDefault();},{passive:false});
document.addEventListener('gesturechange',function(e){e.preventDefault();},{passive:false});
document.addEventListener('gestureend',function(e){e.preventDefault();},{passive:false});
/* Prevent double-tap zoom */
var lastTouchEnd=0;
document.addEventListener('touchend',function(e){var now=Date.now();if(now-lastTouchEnd<=300)e.preventDefault();lastTouchEnd=now;},{passive:false});
//

head.b:skin:
/*=======================================
  CINEMA DARK V20 - KumaStream Redesign
  - Clean post detail with tabs
  - Hero banner with back/heart overlay
  - Server card download format
  - Homepage with Movies + Series sections
  - Bottom nav: Home, Movies, Series, Bookmark, Recent
  Version: 24.1
=======================================*/
:root{
--bg:#0a0a12;--bg2:#11111d;--bg3:#1a1a2e;
--card:#16162a;--card-h:#1e1e3a;
--txt:#fff;--txt2:#9ca3af;--muted:#6b7280;
--accent:#FF4081;--accent2:#E91E63;
--accent-glow:rgba(255,64,129,.25);
--orange:#FF9800;--gold:#FFD700;--red:#FF3B30;
--border:rgba(255,255,255,.08);--border2:rgba(255,255,255,.15);
--r:8px;--r2:12px;--r3:16px;
--shadow:0 8px 32px rgba(0,0,0,.6);
--tr:.3s ease;--max-w:1200px;
--header-h:56px;--bnav-h:50px;
}
*{margin:0;padding:0;box-sizing:border-box}
html{-webkit-tap-highlight-color:transparent;touch-action:manipulation;scroll-behavior:smooth;overflow-x:hidden;width:100%}
body{font-family:'Inter',-apple-system,BlinkMacSystemFont,sans-serif;background:var(--bg);color:var(--txt);line-height:1.6;overflow-x:hidden;touch-action:manipulation;position:relative;width:100%}
body.bn-visible{padding-bottom:calc(var(--bnav-h) + env(safe-area-inset-bottom, 0px))}
a{text-decoration:none;color:inherit;transition:var(--tr)}
a:hover{color:var(--accent)}
img{max-width:100%;height:auto;display:block}
ul,ol{list-style:none}
::selection{background:var(--accent);color:#fff}
::-webkit-scrollbar{width:4px;height:4px}
::-webkit-scrollbar-track{background:var(--bg)}
::-webkit-scrollbar-thumb{background:var(--card);border-radius:2px}
::-webkit-scrollbar-thumb:hover{background:var(--accent)}
.container{max-width:var(--max-w);margin:0 auto;padding:0 12px;width:100%;overflow-x:hidden}

/* ========== HEADER ========== */
.site-header{background:rgba(10,10,18,.97);border-bottom:1px solid var(--border);position:sticky;top:0;z-index:1001;height:var(--header-h)}
.header-inner{display:flex;align-items:center;justify-content:space-between;height:var(--header-h);padding:0 4px;gap:8px}
.logo a{display:flex;align-items:center;gap:6px;font-size:17px;font-weight:800;color:var(--accent);letter-spacing:-.5px}
.logo a i{font-size:20px}
.header-actions{display:flex;align-items:center;gap:2px}
.header-btn{width:38px;height:38px;display:flex;align-items:center;justify-content:center;color:var(--txt2);font-size:17px;background:none;border:none;border-radius:50%;cursor:pointer;transition:var(--tr)}
.header-btn:hover{color:var(--accent);background:rgba(255,64,129,.1)}

/* Hide header on post pages */
body.post-page .site-header{display:none}
body.post-page .search-overlay,
body.post-page .search-bar{display:none!important}
body.post-page .drawer-overlay,
body.post-page .app-drawer{display:none!important}

/* ========== SEARCH ========== */
.search-overlay{position:fixed;inset:0;background:rgba(0,0,0,.7);z-index:1002;opacity:0;visibility:hidden;transition:opacity .25s ease,visibility .25s ease}
.search-overlay.active{opacity:1;visibility:visible}
.search-bar{position:fixed;top:0;left:0;right:0;background:var(--bg2);border-bottom:1px solid var(--border);z-index:1003;padding:12px 16px;transform:translateY(-100%);transition:transform .3s ease}
.search-bar.active{transform:translateY(0)}
.search-bar-inner{display:flex;align-items:center;gap:10px;max-width:600px;margin:0 auto}
.search-bar form{flex:1;display:flex;align-items:center;background:var(--bg3);border:2px solid var(--border);border-radius:50px;overflow:hidden;transition:var(--tr)}
.search-bar form:focus-within{border-color:var(--accent)}
.search-bar input{flex:1;background:0 0;border:none;padding:10px 18px;color:var(--txt);font-family:inherit;font-size:14px;outline:none}
.search-bar input::placeholder{color:var(--muted)}
.search-bar .sb-submit{width:42px;height:42px;background:var(--accent);border:none;color:#fff;cursor:pointer;font-size:14px;display:flex;align-items:center;justify-content:center;transition:var(--tr)}
.search-bar .sb-submit:hover{background:var(--accent2)}
.search-bar .sb-close{width:38px;height:38px;background:none;border:none;color:var(--txt2);font-size:17px;cursor:pointer;border-radius:50%;display:flex;align-items:center;justify-content:center;transition:var(--tr);flex-shrink:0}
.search-bar .sb-close:hover{color:var(--accent);background:rgba(255,64,129,.1)}

/* ========== DRAWER ========== */
.drawer-overlay{position:fixed;inset:0;background:rgba(0,0,0,.6);z-index:1004;opacity:0;visibility:hidden;transition:opacity .25s ease,visibility .25s ease}
.drawer-overlay.active{opacity:1;visibility:visible}
.app-drawer{position:fixed;top:0;left:0;bottom:0;width:280px;max-width:85vw;background:var(--bg2);z-index:1005;transform:translateX(-100%);transition:transform .3s ease;overflow-y:auto;display:flex;flex-direction:column;border-right:1px solid var(--border)}
.app-drawer.active{transform:translateX(0)}
.drawer-header{padding:20px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between}
.dh-logo{display:flex;align-items:center;gap:10px}
.dh-logo-icon{width:40px;height:40px;background:var(--accent);border-radius:50%;display:flex;align-items:center;justify-content:center;color:#fff;font-size:18px}
.dh-logo-text{font-size:15px;font-weight:800;color:var(--accent)}
.dh-logo-sub{font-size:10px;color:var(--txt2);font-weight:500}
.dh-close{width:32px;height:32px;background:none;border:none;color:var(--txt2);font-size:16px;cursor:pointer;border-radius:50%;display:flex;align-items:center;justify-content:center;transition:var(--tr)}
.dh-close:hover{color:var(--accent);background:rgba(255,64,129,.1)}
.drawer-nav{flex:1;padding:8px 0}
.drawer-nav-label{padding:12px 20px 6px;font-size:10px;font-weight:700;color:var(--muted);text-transform:uppercase;letter-spacing:1.5px}
.drawer-nav a{display:flex;align-items:center;gap:12px;padding:11px 20px;color:var(--txt2);font-size:14px;font-weight:500;transition:var(--tr);margin:1px 8px;border-radius:var(--r)}
.drawer-nav a i{width:20px;text-align:center;font-size:15px}
.drawer-nav a:hover{color:var(--accent);background:rgba(255,64,129,.08)}
.drawer-nav a.active{color:var(--accent);background:rgba(255,64,129,.12);font-weight:600}
.drawer-footer{padding:16px 20px;border-top:1px solid var(--border)}
.dfl{display:flex;align-items:center;gap:10px;padding:8px 0;color:var(--txt2);font-size:12px;cursor:pointer;transition:var(--tr)}
.dfl:hover{color:var(--accent)}
.dfl i{width:18px;text-align:center;font-size:13px}
.drawer-fb{margin-top:10px;padding-top:10px;border-top:1px solid var(--border)}
.drawer-fb span{font-size:11px;color:var(--muted);cursor:pointer;display:flex;align-items:center;gap:8px}
.drawer-fb span:hover{color:var(--accent)}

/* ========== SECTION HEADER ========== */
.section-header{display:flex;align-items:center;gap:8px;padding:12px 0 8px}
.section-bar{width:3px;height:18px;background:var(--accent);border-radius:2px;flex-shrink:0}
.section-header h2{font-size:16px;font-weight:700;flex:1;min-width:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.view-all-link{display:inline-flex;align-items:center;gap:4px;font-size:12px;font-weight:600;color:var(--accent);white-space:nowrap;transition:var(--tr);margin-left:8px;flex-shrink:0}
.view-all-link:hover{color:var(--accent2);gap:6px}
.view-all-link i{font-size:10px;transition:var(--tr)}

/* ========== POST GRID (Homepage) ========== */
.post-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;padding:0 0 12px}

/* ========== HOMEPAGE SKELETON ========== */
.home-skeleton{padding:0 0 8px}
.home-skeleton .skel-section-head{display:flex;align-items:center;gap:8px;padding:12px 0 8px}
.home-skeleton .skel-bar{width:3px;height:18px;background:var(--accent);border-radius:2px;opacity:.5}
.home-skeleton .skel-bar-text{width:100px;height:16px;background:var(--bg3);border-radius:6px;position:relative;overflow:hidden}
.home-skeleton .skel-bar-text::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent 0%,rgba(255,255,255,.05) 50%,transparent 100%);background-size:200% 100%;animation:shimmer 1.5s ease-in-out infinite}
.home-skeleton .skel-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;padding:0 0 8px}
.home-skeleton .skel-card{border-radius:var(--r);overflow:hidden;background:var(--card);border:1px solid var(--border)}
.home-skeleton .skel-card-poster{aspect-ratio:2/3;background:var(--bg3);position:relative;overflow:hidden}
.home-skeleton .skel-card-poster::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,var(--bg3) 25%,rgba(255,255,255,.04) 50%,var(--bg3) 75%);background-size:200% 100%;animation:shimmer 1.5s ease-in-out infinite}
.home-skeleton .skel-card-info{padding:8px;height:52px}
.home-skeleton .skel-card-title{height:12px;background:var(--bg3);border-radius:6px;width:80%;margin-bottom:8px;position:relative;overflow:hidden}
.home-skeleton .skel-card-title::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent 0%,rgba(255,255,255,.05) 50%,transparent 100%);background-size:200% 100%;animation:shimmer 1.5s ease-in-out infinite}
.home-skeleton .skel-card-year{height:10px;background:var(--bg3);border-radius:5px;width:40%;position:relative;overflow:hidden}
.home-skeleton .skel-card-year::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent 0%,rgba(255,255,255,.05) 50%,transparent 100%);background-size:200% 100%;animation:shimmer 1.5s ease-in-out infinite}
.home-skeleton.hide{opacity:0;pointer-events:none;position:absolute;width:100%;visibility:hidden}
.grid-card{border-radius:var(--r);overflow:hidden;background:var(--card);border:1px solid var(--border);transition:border-color .3s ease,box-shadow .3s ease;cursor:pointer;contain:layout style paint}
.grid-card:hover{border-color:rgba(255,64,129,.3);box-shadow:var(--shadow)}
.grid-poster{position:relative;aspect-ratio:2/3;overflow:hidden;background:var(--bg3)}
.grid-poster img{width:100%;height:100%;object-fit:cover;opacity:0;transition:opacity .5s ease;will-change:opacity}
.grid-poster img.loaded{opacity:1}
.grid-poster::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,var(--bg3) 25%,rgba(255,255,255,.04) 50%,var(--bg3) 75%);background-size:200% 100%;animation:shimmer 1.5s ease-in-out infinite;z-index:1;opacity:1;transition:opacity .3s ease}
.grid-poster.img-ready::after,.grid-poster:has(.loaded)::after{opacity:0;pointer-events:none}
.grid-quality{position:absolute;top:6px;left:6px;padding:2px 7px;border-radius:4px;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.3px;color:#fff;background:var(--red);z-index:2}
.grid-rating{position:absolute;top:6px;right:6px;background:rgba(0,0,0,.85);padding:2px 6px;border-radius:4px;font-size:10px;font-weight:700;color:#FFD700;display:flex;align-items:center;gap:3px;z-index:2}
.grid-rating i{font-size:8px;color:#FFD700}
.grid-info{padding:8px;height:52px;overflow:hidden}
.grid-title{font-size:12px;font-weight:600;line-height:1.3;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;margin-bottom:3px;color:var(--txt)}
.grid-year{font-size:10px;color:var(--muted);min-height:14px}
.grid-type-badge{position:absolute;bottom:6px;left:6px;padding:2px 7px;border-radius:3px;font-size:8px;font-weight:700;text-transform:uppercase;color:#fff;background:var(--accent);z-index:2}

/* Horizontal scroll for desktop homepage sections */
.genre-scroll{display:flex;gap:12px;overflow-x:auto;-webkit-overflow-scrolling:touch;scrollbar-width:none;padding:4px 0 16px}
.genre-scroll::-webkit-scrollbar{display:none}
.genre-scroll .gc{min-width:150px;max-width:150px;flex-shrink:0;border-radius:var(--r2);overflow:hidden;background:var(--card);border:1px solid var(--border);transition:var(--tr);cursor:pointer}
.genre-scroll .gc:hover{border-color:rgba(255,64,129,.3);transform:translateY(-3px);box-shadow:var(--shadow)}
.genre-scroll .gc-poster{position:relative;aspect-ratio:2/3;overflow:hidden;background:var(--bg3)}
.genre-scroll .gc-poster img{width:100%;height:100%;object-fit:cover;transition:transform .4s ease}
.genre-scroll .gc:hover .gc-poster img{transform:scale(1.05)}
.genre-scroll .gc-info{padding:8px 10px 10px}
.genre-scroll .gc-title{font-size:12px;font-weight:600;line-height:1.3;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;margin-bottom:4px}
.genre-scroll .gc-meta{font-size:10px;color:var(--muted)}
.genre-scroll .gc-badge{position:absolute;top:6px;left:6px;padding:2px 7px;border-radius:3px;font-size:8px;font-weight:700;text-transform:uppercase;letter-spacing:.3px;color:#fff}
.genre-scroll .gc-rating{position:absolute;top:6px;right:6px;background:rgba(0,0,0,.75);backdrop-filter:blur(6px);padding:2px 7px;border-radius:4px;font-size:10px;font-weight:700;color:#fff;display:flex;align-items:center;gap:3px}
.genre-scroll .gc-rating i{color:var(--accent);font-size:8px}

/* ========== POST DETAIL: Hero ========== */
body.post-page .pd-wrap{margin:0}
body.post-page .container{padding:0}
.pd-hero-simple{position:relative;width:100%;height:42vh;min-height:200px;max-height:340px;overflow:hidden;background:var(--bg3)}
.pd-hero-simple img{width:100%;height:100%;object-fit:cover;object-position:center center;transition:opacity .4s ease}
.pd-hero-simple img[src^="data:image"]{opacity:0}
.pd-hero-overlay{position:absolute;bottom:0;left:0;right:0;height:60%;background:linear-gradient(to top,rgba(10,10,18,.9) 0%,rgba(10,10,18,.5) 35%,rgba(10,10,18,0) 100%);pointer-events:none;z-index:2}

.pd-hero-btns{position:absolute;top:12px;left:12px;right:12px;display:flex;justify-content:space-between;z-index:5;pointer-events:auto}
.pd-hero-circle{width:36px;height:36px;border-radius:50%;background:rgba(0,0,0,.5);backdrop-filter:blur(12px);-webkit-backdrop-filter:blur(12px);display:flex;align-items:center;justify-content:center;color:#fff;font-size:14px;cursor:pointer;border:1px solid rgba(255,255,255,.15);transition:var(--tr);box-shadow:0 2px 8px rgba(0,0,0,.3)}
.pd-hero-circle:hover{background:rgba(0,0,0,.65);transform:scale(1.08)}

/* ========== POST DETAIL: Info Card ========== */
.pd-info-card{display:flex;gap:14px;padding:16px;margin:-30px 16px 0;position:relative;z-index:10;background:var(--card);border-radius:var(--r3);border:1px solid var(--border)}
.pd-poster-thumb{width:100px;min-width:100px;height:150px;border-radius:var(--r2);overflow:hidden;border:2px solid var(--border);background:var(--bg3);flex-shrink:0}
.pd-poster-thumb img{width:100%;height:100%;object-fit:cover}
.pd-info-right{flex:1;display:flex;flex-direction:column;justify-content:center;min-width:0}
.pd-info-right h1{font-size:18px;font-weight:800;line-height:1.3;margin-bottom:8px;color:var(--txt)}
.pd-meta-row{display:flex;align-items:center;gap:12px;flex-wrap:wrap;font-size:13px;color:var(--txt2);margin-bottom:10px}
.pd-meta-item{display:flex;align-items:center;gap:4px;font-size:12px;color:var(--txt2)}
.pd-meta-item i{font-size:11px;color:var(--muted)}
.pd-meta-item.rating-item{color:var(--accent)}
.pd-meta-item.rating-item i{color:var(--accent)}
.pd-genre-pills{display:flex;flex-wrap:wrap;gap:6px}
.genre-pill{padding:3px 10px;border-radius:4px;font-size:10px;font-weight:500;color:var(--txt2);background:rgba(255,255,255,.08);border:1px solid var(--border)}

/* ========== POST DETAIL: Tabs ========== */
.pd-tabs{display:flex;margin:16px 16px 0;padding:0;gap:0;border-bottom:1px solid var(--border)}
.pd-tab-btn{flex:1;padding:12px 0;font-size:13px;font-weight:600;color:var(--muted);background:none;border:none;cursor:pointer;position:relative;transition:var(--tr);text-align:center}
.pd-tab-btn:hover{color:var(--txt2)}
.pd-tab-btn.active{color:var(--accent)}
.pd-tab-btn.active::after{content:'';position:absolute;bottom:-1px;left:20%;right:20%;height:3px;background:var(--accent);border-radius:3px 3px 0 0}
.pd-tab-panel{display:none;padding:16px 16px 24px}
.pd-tab-panel.active{display:block}

/* ========== POST DETAIL: Detail Tab ========== */
.pd-overview-title{font-size:15px;font-weight:700;margin-bottom:10px;color:var(--txt)}
.pd-synopsis-text{font-size:13px;line-height:1.8;color:var(--txt2);margin-bottom:10px}
.pd-view-more{display:inline-flex;align-items:center;gap:4px;font-size:12px;font-weight:600;color:var(--accent);cursor:pointer;margin-bottom:16px}
.pd-view-more:hover{text-decoration:underline}
.pd-tech-details{border-top:1px solid var(--border);padding-top:14px}
.pd-tech-details h3{font-size:13px;font-weight:700;margin-bottom:10px;color:var(--txt)}
.pd-tech-list{display:flex;flex-direction:column;gap:8px}
.pd-tech-item{display:flex;align-items:center;gap:10px;padding:10px 12px;background:var(--bg3);border-radius:var(--r);font-size:12px}
.pd-tech-icon{width:32px;height:32px;border-radius:var(--r);background:rgba(255,64,129,.1);display:flex;align-items:center;justify-content:center;color:var(--accent);font-size:13px;flex-shrink:0}
.pd-tech-label{color:var(--muted);font-size:10px;text-transform:uppercase;letter-spacing:.5px;margin-bottom:1px}
.pd-tech-value{color:var(--txt);font-weight:500}

/* ========== POST DETAIL: Download Tab ========== */
.dl-heading{font-size:15px;font-weight:700;margin-bottom:14px;display:flex;align-items:center;gap:8px;color:var(--txt)}
.dl-heading i{color:var(--accent)}
.dl-server-card{background:var(--card);border-radius:var(--r2);border:1px solid var(--border);margin-bottom:10px;overflow:hidden}
.dl-server-header{display:flex;align-items:center;justify-content:space-between;padding:12px 14px;cursor:pointer;transition:var(--tr);user-select:none}
.dl-server-header:hover{background:var(--card-h)}
.dl-server-left{display:flex;align-items:center;gap:10px}
.dl-server-icon{width:32px;height:32px;border-radius:var(--r);background:rgba(255,64,129,.1);display:flex;align-items:center;justify-content:center;color:var(--accent);font-size:13px;flex-shrink:0}
.dl-server-name{font-size:13px;font-weight:600;color:var(--txt)}
.dl-server-qualities{display:flex;gap:4px;margin-top:3px;flex-wrap:wrap}
.dl-server-quality-tag{padding:1px 6px;border-radius:3px;font-size:9px;font-weight:600;color:var(--accent);background:rgba(255,64,129,.1)}
.dl-server-arrow{color:var(--muted);font-size:12px;transition:transform .3s ease}
.dl-server-card.expanded .dl-server-arrow{transform:rotate(180deg)}
.dl-server-body{display:none;padding:0 14px 14px;border-top:1px solid var(--border)}
.dl-server-card.expanded .dl-server-body{display:block}
.dl-quality-card{margin-top:10px;padding:12px;background:var(--bg3);border-radius:var(--r);border:1px solid var(--border)}
.dl-quality-top{display:flex;align-items:center;gap:8px;margin-bottom:6px}
.dl-quality-badge{padding:3px 10px;border-radius:50px;font-size:10px;font-weight:700;color:#fff;background:var(--red);text-transform:uppercase;letter-spacing:.3px}
.dl-quality-label{font-size:13px;font-weight:600;color:var(--txt)}
.dl-quality-info{font-size:11px;color:var(--muted);margin-bottom:10px}
.dl-download-btn{display:flex;align-items:center;justify-content:center;gap:8px;width:100%;padding:10px;background:var(--red);color:#fff;border:none;border-radius:var(--r);font-size:13px;font-weight:600;cursor:pointer;transition:var(--tr)}
.dl-download-btn:hover{background:#e6352b;transform:translateY(-1px)}
.dl-download-btn i{font-size:12px}

/* ========== POST DETAIL: Explore Tab ========== */
.explore-heading{font-size:15px;font-weight:700;margin-bottom:14px;display:flex;align-items:center;gap:8px;color:var(--txt)}
.explore-heading i{color:var(--accent)}
.explore-scroll{display:grid;grid-template-columns:repeat(3,1fr);gap:10px;padding:4px 0 20px}
.explore-scroll::-webkit-scrollbar{display:none}
.explore-card{border-radius:var(--r);overflow:hidden;background:var(--card);border:1px solid var(--border);transition:border-color .3s ease,transform .3s ease;cursor:pointer;contain:layout style paint}
.explore-card:hover{border-color:rgba(255,64,129,.3);transform:translateY(-3px);box-shadow:var(--shadow)}
.explore-poster{position:relative;aspect-ratio:2/3;overflow:hidden;background:var(--bg3)}
.explore-poster img{width:100%;height:100%;object-fit:cover;transition:transform .4s ease}
.explore-card:hover .explore-poster img{transform:scale(1.05)}
.explore-qbadge{position:absolute;top:6px;left:6px;padding:2px 7px;border-radius:4px;font-size:9px;font-weight:700;text-transform:uppercase;color:#fff;background:var(--red)}
.explore-rbadge{position:absolute;top:6px;right:6px;background:rgba(0,0,0,.85);padding:2px 6px;border-radius:4px;font-size:10px;font-weight:700;color:#FFD700;display:flex;align-items:center;gap:3px}
.explore-rbadge i{font-size:8px;color:#FFD700}
.explore-info{padding:8px 10px}
.explore-title{font-size:12px;font-weight:600;line-height:1.35;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;color:var(--txt)}
.explore-year{font-size:10px;color:var(--muted);margin-top:3px}

/* Hidden post body (for JS parsing) */
.pd-body-raw{display:none!important}

/* ========== BOTTOM NAV ========== */
.bottom-nav{position:fixed;bottom:0;left:0;right:0;width:100%;max-width:100vw;height:var(--bnav-h);background:rgba(10,10,18,.97);border-top:1px solid var(--border);z-index:1000;display:flex;align-items:center;justify-content:space-around;box-sizing:border-box;will-change:transform;transform:translateZ(0);backface-visibility:hidden;-webkit-backface-visibility:hidden}
.bn-item{display:flex;flex-direction:column;align-items:center;justify-content:center;gap:1px;color:var(--muted);font-size:9px;font-weight:500;cursor:pointer;transition:color .2s ease;padding:0 8px;border:none;background:none;-webkit-tap-highlight-color:transparent}
.bn-item i{font-size:15px;transition:var(--tr)}
.bn-item:hover{color:var(--accent)}
.bn-item.active{color:var(--accent)}
.bn-item.active i{transform:scale(1.1)}

/* ========== FOOTER ========== */
.site-footer{background:var(--bg2);border-top:1px solid var(--border);padding:20px 0 0;margin-top:20px}
.footer-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:20px;padding-bottom:20px}
.footer-col h4{font-size:13px;font-weight:700;margin-bottom:12px;display:flex;align-items:center;gap:6px}
.footer-col h4 i{color:var(--accent);font-size:12px}
.footer-about p{color:var(--txt2);font-size:12px;line-height:1.8;margin-bottom:10px}
.footer-links li{margin-bottom:5px}
.footer-links li a{color:var(--txt2);font-size:12px;display:flex;align-items:center;gap:6px}
.footer-links li a:hover{color:var(--accent);padding-left:4px}
.footer-bottom{border-top:1px solid var(--border);padding:10px 0;text-align:center}
.footer-bottom p{color:var(--muted);font-size:11px}

/* ========== SIDEBAR ========== */
.main-layout{display:grid;grid-template-columns:1fr;gap:0;padding:0;overflow:hidden}
.sidebar{display:none}
.sidebar-widget{background:var(--card);border-radius:var(--r2);border:1px solid var(--border);overflow:hidden}
.sw-title{padding:12px 14px;font-size:13px;font-weight:700;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:8px}
.sw-title i{color:var(--accent)}
.sw-content{padding:12px}
.popular-list{display:flex;flex-direction:column;gap:8px}
.popular-item{display:flex;gap:10px;align-items:flex-start}
.popular-num{width:24px;height:24px;background:var(--bg3);border-radius:5px;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;color:var(--accent);flex-shrink:0}
.popular-item:nth-child(1) .popular-num{background:var(--accent);color:#fff}
.popular-item:nth-child(2) .popular-num{background:var(--orange);color:#fff}
.popular-item:nth-child(3) .popular-num{background:var(--gold);color:#000}
.popular-text h4{font-size:12px;font-weight:500;line-height:1.4;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;margin-bottom:2px}
.popular-text h4 a:hover{color:var(--accent)}
.popular-text span{font-size:10px;color:var(--muted)}
.label-list{display:flex;flex-wrap:wrap;gap:5px}
.label-list a{display:inline-block;padding:4px 10px;background:var(--bg3);border:1px solid var(--border);border-radius:50px;color:var(--txt2);font-size:11px;font-weight:500;transition:var(--tr)}
.label-list a:hover{background:var(--accent);border-color:var(--accent);color:#fff}
.sidebar-ad{background:var(--bg3);border:1px dashed var(--border);border-radius:var(--r2);padding:18px;text-align:center}
.sidebar-ad i{font-size:26px;color:var(--muted);margin-bottom:8px}
.sidebar-ad p{color:var(--muted);font-size:11px}

/* ========== UTILITY ========== */
.hidden-el{display:none!important}
.empty-msg{text-align:center;padding:30px 16px;color:var(--txt2)}
.empty-msg i{font-size:32px;color:var(--muted);display:block;margin-bottom:10px}
.empty-msg small{font-size:11px;color:var(--muted)}

/* ========== 404 ERROR PAGE ========== */
.error-404{display:flex;flex-direction:column;align-items:center;justify-content:center;min-height:80vh;padding:40px 24px;text-align:center}
.error-404-icon{font-size:100px;font-weight:900;color:var(--accent);line-height:1;margin-bottom:16px;text-shadow:0 0 60px var(--accent-glow),0 0 120px rgba(255,64,129,.1);position:relative}
.error-404-icon::after{content:'';position:absolute;inset:-20px;border-radius:50%;background:radial-gradient(circle,rgba(255,64,129,.08) 0%,transparent 70%);z-index:-1}
.error-404 h2{font-size:22px;font-weight:700;color:var(--txt);margin-bottom:10px}
.error-404 p{font-size:14px;color:var(--txt2);line-height:1.7;margin-bottom:28px;max-width:340px}
.error-404-btn{display:inline-flex;align-items:center;gap:8px;padding:12px 32px;background:var(--accent);color:#fff;border:none;border-radius:50px;font-size:14px;font-weight:600;cursor:pointer;transition:var(--tr);box-shadow:0 4px 20px var(--accent-glow);text-decoration:none}
.error-404-btn:hover{background:var(--accent2);transform:translateY(-2px);box-shadow:0 6px 30px var(--accent-glow)}
.error-404-btn i{font-size:13px}
.back-top{position:fixed;bottom:calc(var(--bnav-h) + 14px);right:16px;width:38px;height:38px;background:var(--accent);border-radius:50%;display:flex;align-items:center;justify-content:center;color:#fff;font-size:14px;cursor:pointer;opacity:0;visibility:hidden;transition:var(--tr);z-index:999;box-shadow:0 4px 16px var(--accent-glow)}
.back-top.visible{opacity:1;visibility:visible}
.back-top:hover{background:var(--accent2);transform:translateY(-2px)}
.pagination{display:flex;align-items:center;justify-content:center;gap:6px;padding:16px 0}
.pagination a,.pagination span{display:flex;align-items:center;justify-content:center;min-width:36px;height:36px;background:var(--card);border:1px solid var(--border);border-radius:var(--r);color:var(--txt2);font-size:13px;font-weight:500;transition:var(--tr);padding:0 4px}
.pagination a:hover,.pagination span.active{background:var(--accent);border-color:var(--accent);color:#fff}
.pagination span.active{cursor:default;pointer-events:none}

/* Post body fallback */
.post-body{color:var(--txt2);font-size:14px;line-height:1.85}
.post-body table{width:100%;border-collapse:collapse;margin:12px 0}
.post-body td,.post-body th{padding:8px 12px;border:1px solid var(--border);font-size:13px}
.post-body a{color:var(--accent)}
.post-body img{border-radius:var(--r);margin:8px 0}
.post-body br{display:block;content:'';margin-top:4px}

/* ========== HIDE BLOGGER DEFAULTS ========== */
body.post-page .main-layout{grid-template-columns:1fr;padding:0;gap:0}
body.post-page .main-content{padding:0}
/* container padding removed for post pages - handled by pd-wrap children */
body.post-page .pd-wrap{margin:0}
body.post-page .pd-info-card{margin-left:16px;margin-right:16px}
body.post-page .site-footer{display:none}
.blog-posts{display:none!important}
.blog-pager,.widget .blog-pager,.feed-links,.blog-feeds{display:none!important}
.status-msg-wrap,.status-msg-body,.status-msg-border{display:none!important}
body:not(.post-page) .post-outer-container{display:none!important}
body:not(.post-page) .post-footer{display:none!important}
body:not(.post-page) .post-share-buttons{display:none!important}
body:not(.post-page) .post-comment-link{display:none!important}
body:not(.post-page) .post-timestamp{display:none!important}
body:not(.post-page) .post-title{display:none!important}
body:not(.post-page) .post-body{display:none!important}
body:not(.post-page) .post-header{display:none!important}
body:not(.post-page) .entry-content{display:none!important}
body:not(.post-page) .post-snippet{display:none!important}
body:not(.post-page) .post-summary{display:none!important}
body:not(.post-page) .comment-link{display:none!important}
.widget ul{list-style:none}
#comments{background:none}
body.no-scroll{overflow:hidden}

/* ========== ANIMATIONS ========== */
@keyframes shimmer{0%{background-position:200% 0}100%{background-position:-200% 0}}

/* ========== POST DETAIL: Skeleton Loading ========== */
.skel{position:relative;overflow:hidden;background:var(--bg3);border-radius:var(--r)}
.skel::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent 0%,rgba(255,255,255,.05) 50%,transparent 100%);background-size:200% 100%;animation:shimmer 1.5s ease-in-out infinite}
.skel-hero{width:100%;height:42vh;min-height:200px;max-height:340px;border-radius:0}
.skel-info{display:flex;gap:14px;padding:16px;margin:-30px 16px 0;position:relative;z-index:10;background:var(--card);border-radius:var(--r3);border:1px solid var(--border)}
.skel-poster{width:100px;min-width:100px;height:150px;border-radius:var(--r2)}
.skel-lines{flex:1;display:flex;flex-direction:column;gap:8px;padding-top:8px}
.skel-line{height:12px;background:var(--bg3);border-radius:6px;position:relative;overflow:hidden}
.skel-line::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent 0%,rgba(255,255,255,.05) 50%,transparent 100%);background-size:200% 100%;animation:shimmer 1.5s ease-in-out infinite}
.skel-line.w60{width:60%}.skel-line.w80{width:80%}.skel-line.w40{width:40%}.skel-line.w70{width:70%}
.skel-pills{display:flex;gap:6px;margin-top:4px}
.skel-pill{height:22px;width:60px;background:var(--bg3);border-radius:4px;position:relative;overflow:hidden}
.skel-pill::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent 0%,rgba(255,255,255,.05) 50%,transparent 100%);background-size:200% 100%;animation:shimmer 1.5s ease-in-out infinite}
.skel-tabs{display:flex;margin:16px 16px 0;padding:0;gap:0;border-bottom:1px solid var(--border)}
.skel-tab{flex:1;height:12px;margin:12px 0;background:var(--bg3);border-radius:6px;position:relative;overflow:hidden}
.skel-tab::after{content:'';position:absolute;inset:0;background:linear-gradient(90deg,transparent 0%,rgba(255,255,255,.05) 50%,transparent 100%);background-size:200% 100%;animation:shimmer 1.5s ease-in-out infinite}
.skel-content{padding:16px;display:flex;flex-direction:column;gap:10px}
#pdSkeleton{transition:opacity .3s ease}
#pdSkeleton.hide{opacity:0;pointer-events:none;position:absolute;width:100%;visibility:hidden}
#pdWrap{opacity:0;transition:opacity .3s ease}
#pdWrap.show{opacity:1}
/* genre-scroll cards - no animation */

/* ========== RESPONSIVE ========== */

/* ===== Desktop: 1200px+ ===== */
@media(min-width:1200px){
  .container{padding:0 20px}
  .header-inner{padding:0 8px}
  .logo a{font-size:20px}
  .logo a i{font-size:24px}
  .post-grid{grid-template-columns:repeat(6,1fr);gap:14px}
  .home-skeleton .skel-grid{grid-template-columns:repeat(6,1fr);gap:14px}
  .genre-scroll{display:none!important}
  .mobile-grid{display:grid!important}
  .pd-hero-simple{height:48vh;min-height:300px;max-height:400px}
  .pd-info-card{margin:-40px 24px 0;padding:20px;gap:16px}
  body.post-page .pd-info-card{margin-left:24px;margin-right:24px}
  .pd-poster-thumb{width:120px;min-width:120px;height:180px}
  .pd-info-right h1{font-size:22px}
  .pd-tabs{margin:20px 24px 0}
  .pd-tab-btn{font-size:14px;padding:14px 0}
  .pd-tab-panel{padding:20px 24px 28px}
  .section-header{padding:16px 0 10px}
  .section-header h2{font-size:18px}
  .view-all-link{font-size:13px}
  .grid-info{height:56px;padding:10px}
  .grid-title{font-size:13px}
  .grid-year{font-size:11px}
  .explore-scroll{grid-template-columns:repeat(3,1fr);gap:14px}
  .pagination a,.pagination span{min-width:40px;height:40px;font-size:14px}
}

/* ===== Tablet: 769px - 1199px ===== */
@media(min-width:769px) and (max-width:1199px){
  .post-grid{grid-template-columns:repeat(4,1fr)}
  .home-skeleton .skel-grid{grid-template-columns:repeat(4,1fr)}
  .genre-scroll .gc{min-width:160px;max-width:160px}
  .pd-info-card{margin:-35px 20px 0}
  body.post-page .pd-info-card{margin-left:20px;margin-right:20px}
}

/* ===== Large Phone: 481px - 768px ===== */
@media(max-width:768px){
  .pd-hero-simple{height:40vh;min-height:180px;max-height:300px}
  .pd-info-card{flex-direction:row;gap:12px;padding:14px;margin:-30px 12px 0}
  body.post-page .pd-info-card{margin-left:12px;margin-right:12px}
  .pd-poster-thumb{width:90px;min-width:90px;height:135px}
  .pd-info-right h1{font-size:16px}
  .footer-grid{grid-template-columns:1fr}
  .container{padding:0 10px}
  .explore-scroll{grid-template-columns:repeat(3,1fr);gap:8px}
  .explore-info{padding:5px 6px}
  .explore-title{font-size:10px}
  .grid-card:hover{transform:none}
  .post-grid{grid-template-columns:repeat(4,1fr)}
  .home-skeleton .skel-grid{grid-template-columns:repeat(4,1fr)}
  .grid-info{height:48px}
  .grid-title{font-size:11px}
  .genre-scroll .gc{min-width:130px;max-width:130px}
}

/* ===== Small Phone: 480px and below ===== */
@media(max-width:480px){
  .pd-hero-simple{height:38vh;min-height:170px;max-height:280px}
  .pd-info-card{gap:10px;padding:12px;margin:-28px 10px 0}
  body.post-page .pd-info-card{margin-left:10px;margin-right:10px}
  .pd-poster-thumb{width:80px;min-width:80px;height:120px}
  .pd-info-right h1{font-size:15px}
  .pd-meta-row{gap:8px}
  .grid-info{height:44px;padding:6px}
  .post-grid{grid-template-columns:repeat(4,1fr);gap:8px}
  .home-skeleton .skel-grid{grid-template-columns:repeat(4,1fr);gap:8px}
  .explore-scroll{grid-template-columns:repeat(3,1fr);gap:6px}
  .explore-title{font-size:9px}
  .section-header h2{font-size:14px}
  .view-all-link{font-size:11px}
  .pd-tab-btn{font-size:12px;padding:10px 0}
}

/* ===== Desktop: hide mobile nav ===== */
@media(min-width:769px){
  .bottom-nav{display:none}
  body{padding-bottom:0!important}
  .back-top{bottom:20px}
}

body.script:
//
(function(){

/* ===== Custom CSS Injection ===== */
function injectCSS(){
  var s=document.getElementById('customCSSStore');
  if(!s)return;
  var t=(s.textContent||'').trim();
  if(!t||t.indexOf('Custom CSS')!==-1)return;
  var st=document.getElementById('dynCSS');
  if(st){st.textContent=t;}
  else{var e=document.createElement('style');e.id='dynCSS';e.textContent=t;document.head.appendChild(e);}
}

/* ===== Drawer Menu ===== */
var menuBtn=document.getElementById('menuBtn');
var drawer=document.getElementById('appDrawer');
var drawerOv=document.getElementById('drawerOverlay');
var drawerClose=document.getElementById('drawerClose');
var bnBookmark=document.getElementById('bnBookmark');
var bnRecent=document.getElementById('bnRecent');

function openDrawer(){drawer.classList.add('active');drawerOv.classList.add('active');document.body.classList.add('no-scroll');}
function closeDrawer(){drawer.classList.remove('active');drawerOv.classList.remove('active');document.body.classList.remove('no-scroll');}

if(menuBtn)menuBtn.addEventListener('click',openDrawer);
if(drawerClose)drawerClose.addEventListener('click',closeDrawer);
if(drawerOv)drawerOv.addEventListener('click',closeDrawer);
if(bnBookmark)bnBookmark.addEventListener('click',openDrawer);
if(bnRecent)bnRecent.addEventListener('click',openDrawer);

var dLinks=drawer?drawer.querySelectorAll('.drawer-nav a'):[];
for(var i=0;i<dLinks.length;i++){dLinks[i].addEventListener('click',closeDrawer);}

/* ===== Search ===== */
var searchBar=document.getElementById('searchBar');
var searchOv=document.getElementById('searchOverlay');
var searchInput=null;
var searchBtn=document.getElementById('searchBtn');
var searchCloseBtn=document.getElementById('searchClose');

function openSearch(){searchBar.classList.add('active');searchOv.classList.add('active');document.body.classList.add('no-scroll');setTimeout(function(){if(searchInput)searchInput.focus();},350);}
function closeSearch(){searchBar.classList.remove('active');searchOv.classList.remove('active');document.body.classList.remove('no-scroll');}

if(searchBtn)searchBtn.addEventListener('click',openSearch);
if(searchCloseBtn)searchCloseBtn.addEventListener('click',closeSearch);
if(searchOv)searchOv.addEventListener('click',closeSearch);
if(searchBar){searchInput=searchBar.querySelector('input');}

/* ===== Back to Top ===== */
var bt=document.getElementById('backTop');
if(bt){
  window.addEventListener('scroll',function(){bt.classList.toggle('visible',window.pageYOffset>300);});
  bt.addEventListener('click',function(e){e.preventDefault();window.scrollTo({top:0,behavior:'smooth'});});
}

/* ===== Footer Year ===== */
var fy=document.getElementById('footerYear');
if(fy)fy.textContent=new Date().getFullYear();

/* ===== ESC Key ===== */
document.addEventListener('keydown',function(e){
  if(e.key==='Escape'){closeDrawer();closeSearch();}
});

/* ===== Heart Toggle ===== */
var heartBtn=document.getElementById('pdHeartBtn');
if(heartBtn){
  heartBtn.addEventListener('click',function(){
    var icon=this.querySelector('i');
    if(icon.classList.contains('far')){
      icon.classList.remove('far');
      icon.classList.add('fas');
      icon.style.color='var(--red)';
    }else{
      icon.classList.remove('fas');
      icon.classList.add('far');
      icon.style.color='';
    }
  });
}

/* ===== Utility Functions ===== */
function extractYear(d){if(!d)return'';var y=new Date(d).getFullYear();return isNaN(y)?'':y;}
function getRating(lbl){var n=(lbl||'').trim();var m=n.match(/Rating[-:\s]*(\d+\.?\d*)/i);if(m)return m[1];m=n.match(/IMDb\s*Rating\s*\(?\s*([\d.]+)\s*\)?/i);if(m)return m[1];return null;}
function getDuration(lbl){var n=(lbl||'').trim();var m=n.match(/Duration[-:\s]*(\d{1,2}:\d{2}(?::\d{2})?)/i);return m?m[1]:null;}
var SKIP=['Movie','Movies','Series','Rating','Duration','IMDb','zDub','Subtitle','Language','Dub','Season','Episode','Bluray','BluRay','HD','HDRip','DVDRip','WebRip','WebDL','CAM','HDCAM','HDTV','BDRip','DVDScr','PPV','REMUX','Remux','Proper','Repack'];
function isGenre(n){var t=(n||'').trim();for(var i=0;i<SKIP.length;i++){if(t===SKIP[i])return false;}if(/Rating/i.test(t))return false;if(/^Duration/i.test(t))return false;if(/^\d/.test(t))return false;return true;}
var PLACEHOLDER='https://via.placeholder.com/400x600/16162a/FF4081?text=No+Poster';

/* ===== HOMEPAGE: Build Sections ===== */
function buildHomepage(){
  var store=document.getElementById('postStore');
  if(!store)return;
  var items=store.querySelectorAll('.ps-item');
  if(items.length===0)return;
  var posts=[];
  for(var i=0;i<items.length;i++){
    var it=items[i];
    var labels=[];
    var lEls=it.querySelectorAll('.ps-label');
    for(var j=0;j<lEls.length;j++){var v=lEls[j].textContent.trim();if(v)labels.push(v);}
    var imgUrl='';
    var imgEl=it.querySelector('.ps-img');
    if(imgEl)imgUrl=imgEl.textContent.trim();
    /* Extract Poster URL from post body using fast regex (no DOM creation) */
    var posterFromBody='';
    try{
      var bodyEl=it.querySelector('.ps-body');
      if(bodyEl){
        var bhtml=bodyEl.value||bodyEl.textContent||'';
        /* Fast regex: find <h2>Poster</h2> then <img src="..."> */
        var pMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Poster[\s]*<\/h[2-4]>\s*<img[^>]*src\s*=\s*["']([^"']+)["']/i);
        if(!pMatch)pMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Poster[\s]*<\/h[2-4]>\s*<a[^>]*href\s*=\s*["']([^"']+)["']/i);
        if(!pMatch)pMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Poster[\s]*<\/h[2-4]>[\s\S]*?<img[^>]*src\s*=\s*["']([^"']+)["']/i);
        if(pMatch)posterFromBody=pMatch[1];
        /* Fallback: img with alt=poster or class containing poster */
        if(!posterFromBody){
          var altMatch=bhtml.match(/<img[^>]+alt\s*=\s*["'][^"']*poster[^"']*["'][^>]*src\s*=\s*["']([^"']+)["']/i);
          if(!altMatch)altMatch=bhtml.match(/<img[^>]+src\s*=\s*["']([^"']+)["'][^>]*alt\s*=\s*["'][^"']*poster[^"']*["']/i);
          if(altMatch)posterFromBody=altMatch[1];
        }
      }
    }catch(e){}
    var finalImg=posterFromBody||imgUrl||PLACEHOLDER;
    posts.push({
      url:(it.querySelector('.ps-url')||{}).textContent?it.querySelector('.ps-url').textContent.trim():'',
      title:(it.querySelector('.ps-title')||{}).textContent?it.querySelector('.ps-title').textContent.trim():'',
      img:finalImg,
      date:(it.querySelector('.ps-date')||{}).textContent?it.querySelector('.ps-date').textContent.trim():'',
      labels:labels
    });
  }
  /* Remove postStore from DOM to free memory - we only need the data now */
  store.innerHTML='';

  var url=window.location.href;
  var isHomepage=url.indexOf('/search/')===-1&&url.indexOf('/p/')===-1;
  var container=document.getElementById('homeSections');
  if(!container)return;
  var html='';

  function getPostRating(labels){for(var r=0;r<labels.length;r++){var rt=getRating(labels[r]);if(rt)return rt;}return null;}
  function getPostQuality(labels){var q='HD';for(var j=0;j<labels.length;j++){var lb=labels[j].trim();if(/4K|2160p/i.test(lb))return'4K';if(/1080p/i.test(lb))return'1080p';if(/720p/i.test(lb))return'720p';if(/BluRay|Blu-ray/i.test(lb))return'BluRay';}return q;}
  function isType(labels,type){for(var j=0;j<labels.length;j++){if(labels[j].trim()===type)return true;}return false;}
  function renderCard(p,cls){
    var rating=getPostRating(p.labels);
    var quality=getPostQuality(p.labels);
    var year=extractYear(p.date);
    var isSeries=isType(p.labels,'Series');
    var h='<a href="'+p.url+'" class="'+(cls||'grid-card')+'">';
    if(cls==='gc'){
      h+='<div class="gc-poster">';
      h+='<img src="" data-src="'+p.img+'" alt="'+p.title+'" onerror="this.src=\''+PLACEHOLDER+'\'" decoding="async"/>';
      h+='<span class="gc-badge">'+quality+'</span>';
      if(rating)h+='<span class="gc-rating"><i class="fas fa-star"></i> '+rating+'</span>';
      h+='</div><div class="gc-info"><div class="gc-title">'+p.title+'</div>';
      if(year)h+='<div class="gc-meta">'+year+'</div>';
      h+='</div>';
    }else{
      h+='<div class="grid-poster">';
      h+='<img src="" data-src="'+p.img+'" alt="'+p.title+'" onerror="this.src=\''+PLACEHOLDER+'\'" decoding="async"/>';
      h+='<span class="grid-quality">'+quality+'</span>';
      if(rating)h+='<span class="grid-rating"><i class="fas fa-star"></i> '+rating+'</span>';
      if(isSeries)h+='<span class="grid-type-badge">Series</span>';
      h+='</div><div class="grid-info"><div class="grid-title">'+p.title+'</div>';
      if(year)h+='<div class="grid-year">'+year+'</div>';
      h+='</div>';
    }
    h+='</a>';
    return h;
  }

  if(isHomepage){
    /* Homepage: Movies + Series grid sections (10 posts each) */
    var moviePosts=[],seriesPosts=[];
    for(var i=0;i<posts.length;i++){
      if(isType(posts[i].labels,'Series'))seriesPosts.push(posts[i]);
      else moviePosts.push(posts[i]);
    }
    var homeLimit=10;
    var movieHome=moviePosts.slice(0,homeLimit);
    var seriesHome=seriesPosts.slice(0,homeLimit);
    var blogHome=window.location.href.replace(/\/$/,'');
    if(moviePosts.length>0){
      html+='<div class="section-header"><div class="section-bar"></div><h2><i class="fas fa-film" style="color:var(--accent);margin-right:6px"></i>Movies</h2>';
      html+='<a class="view-all-link" href="'+blogHome+'/search/label/Movie">View All <i class="fas fa-chevron-right"></i></a>';
      html+='</div>';
      html+='<div class="post-grid">';
      for(var i=0;i<movieHome.length;i++)html+=renderCard(movieHome[i],'grid-card');
      html+='</div>';
    }
    if(seriesPosts.length>0){
      html+='<div class="section-header"><div class="section-bar"></div><h2><i class="fas fa-tv" style="color:var(--accent);margin-right:6px"></i>Series</h2>';
      html+='<a class="view-all-link" href="'+blogHome+'/search/label/Series">View All <i class="fas fa-chevron-right"></i></a>';
      html+='</div>';
      html+='<div class="post-grid">';
      for(var i=0;i<seriesHome.length;i++)html+=renderCard(seriesHome[i],'grid-card');
      html+='</div>';
    }
  }else{
    /* Label/Search page: single grid */
    var heading='All Posts';
    if(url.indexOf('/search/label/Movie')!==-1)heading='Movies';
    else if(url.indexOf('/search/label/Series')!==-1)heading='Series';
    else if(url.indexOf('/search')!==-1)heading='Search Results';
    html+='<div class="section-header"><div class="section-bar"></div><h2><i class="fas fa-th-large" style="color:var(--accent);margin-right:6px"></i>'+heading+'</h2></div>';
    html+='<div class="post-grid">';
    for(var i=0;i<posts.length;i++)html+=renderCard(posts[i],'grid-card');
    html+='</div>';
  }
  container.innerHTML=html;
  /* Hide homepage skeleton */
  var homeSkel=document.getElementById('homeSkeleton');
  if(homeSkel)homeSkel.classList.add('hide');
  /* Build pagination for label/search pages */
  if(!isHomepage){
    buildPagination(url, posts.length);
  }
  /* Lazy load images with IntersectionObserver for smooth scrolling */
  var lazyImgs=container.querySelectorAll('img[data-src]');
  if(lazyImgs.length>0&&'IntersectionObserver'in window){
    var imgObs=new IntersectionObserver(function(entries){
      for(var e=0;e<entries.length;e++){
        if(entries[e].isIntersecting){
          var img=entries[e].target;
          if(img.dataset.src){
            img.src=img.dataset.src;
            img.removeAttribute('data-src');
          }
          img.addEventListener('load',function(){this.classList.add('loaded');var poster=this.parentElement;if(poster&&poster.classList)poster.classList.add('img-ready');},{once:true});
          imgObs.unobserve(img);
        }
      }
    },{rootMargin:'300px'});
    for(var li=0;li<lazyImgs.length;li++){
      imgObs.observe(lazyImgs[li]);
    }
  }else{
    /* Fallback: load all images immediately */
    var allImgs=container.querySelectorAll('img[data-src]');
    for(var ai=0;ai<allImgs.length;ai++){
      allImgs[ai].src=allImgs[ai].dataset.src;
      allImgs[ai].classList.add('loaded');
      var pEl=allImgs[ai].parentElement;
      if(pEl&&pEl.classList)pEl.classList.add('img-ready');
    }
  }
}

/* ===== PAGINATION (Label/Search Pages) ===== */
var POSTS_PER_PAGE=20;
function buildPagination(url, totalPosts){
  var pagEl=document.getElementById('homePagination');
  if(!pagEl)return;
  /* Determine current page from URL */
  var currentPage=1;
  var siMatch=url.match(/[?&]start-index=(\d+)/i);
  if(siMatch)currentPage=Math.ceil(parseInt(siMatch[1],10)/POSTS_PER_PAGE);
  /* Build base URL */
  var baseUrl=url.replace(/[?&].*/,'').replace(/\/$/,'');
  /* Determine if this is a label or search page */
  var labelMatch=url.match(/\/search\/label\/([^?&]+)/);
  var searchQMatch=url.match(/[?&]q=([^&]+)/);
  var baseQuery='';
  if(labelMatch)baseQuery='/search/label/'+labelMatch[1];
  else if(searchQMatch)baseQuery='/search?q='+searchQMatch[1];
  else baseQuery='';
  if(!baseQuery){pagEl.innerHTML='';return;}
  /* Total items loaded to determine if next page exists */
  var loadedCount=totalPosts||posts.length||0;
  /* Estimate total pages (Blogger max 500 posts per feed) */
  var totalPages=currentPage;
  if(loadedCount>=POSTS_PER_PAGE)totalPages=currentPage+2;
  var html='<div class="pagination">';
  /* Prev arrow */
  if(currentPage>1){
    var prevStart=(currentPage-2)*POSTS_PER_PAGE+1;
    html+='<a href="'+baseUrl+baseQuery+'?&max-results='+POSTS_PER_PAGE+'&start-index='+prevStart+'"><i class="fas fa-chevron-left"></i></a>';
  }
  /* Page numbers */
  var startP=Math.max(1,currentPage-2);
  var endP=Math.min(totalPages,currentPage+2);
  for(var p=startP;p<=endP;p++){
    if(p===currentPage){
      html+='<span class="active">'+p+'</span>';
    }else{
      var startIdx=(p-1)*POSTS_PER_PAGE+1;
      var pageUrl=baseUrl+baseQuery+'?&max-results='+POSTS_PER_PAGE+'&start-index='+startIdx;
      html+='<a href="'+pageUrl+'">'+p+'</a>';
    }
  }
  /* Next arrow */
  if(loadedCount>=POSTS_PER_PAGE){
    var nextStart=currentPage*POSTS_PER_PAGE+1;
    html+='<a href="'+baseUrl+baseQuery+'?&max-results='+POSTS_PER_PAGE+'&start-index='+nextStart+'"><i class="fas fa-chevron-right"></i></a>';
  }
  html+='</div>';
  pagEl.innerHTML=html;
}

/* ===== POST DETAIL: Tabs ===== */
function initTabs(){
  var tabBtns=document.querySelectorAll('.pd-tab-btn');
  var panels=document.querySelectorAll('.pd-tab-panel');
  for(var i=0;i<tabBtns.length;i++){
    tabBtns[i].addEventListener('click',function(){
      var tab=this.getAttribute('data-tab');
      for(var j=0;j<tabBtns.length;j++)tabBtns[j].classList.remove('active');
      for(var j=0;j<panels.length;j++)panels[j].classList.remove('active');
      this.classList.add('active');
      var target=document.getElementById('tab'+tab.charAt(0).toUpperCase()+tab.slice(1));
      if(target)target.classList.add('active');
      /* Load explore on first click */
      if(tab==='explore'&&!exploreLoaded){loadExplore();exploreLoaded=true;}
    });
  }
}

/* ===== POST DETAIL: Process Labels & Meta ===== */
function processPostDetail(){
  var rEl=document.getElementById('postRating');
  if(!rEl)return;

  var labels=[];
  if(window._pl&&Array.isArray(window._pl)&&window._pl.length>0){
    labels=window._pl.slice();
  }
  if(labels.length===0){
    var wrap=document.getElementById('pdWrap');
    if(wrap){
      var spans=wrap.querySelectorAll('.label-data');
      for(var i=0;i<spans.length;i++){var v=spans[i].textContent.trim();if(v)labels.push(v);}
    }
  }
  if(labels.length===0){
    var feedUrl=window.location.origin+'/feeds/posts/default/'+encodeURIComponent(window.location.pathname.split('/').pop())+'?alt=json';
    fetch(feedUrl).then(function(r){return r.json();}).then(function(d){
      var lbs=[];
      if(d.entry&&d.entry.category){d.entry.category.forEach(function(c){if(c.term)lbs.push(c.term);});}
      applyPostMeta(lbs);
    }).catch(function(){});
    return;
  }
  applyPostMeta(labels);
}

function applyPostMeta(labels){
  /* Rating */
  var rating=null;
  for(var i=0;i<labels.length;i++){var r=getRating(labels[i]);if(r){rating=r;break;}}
  var rEl=document.getElementById('postRating');
  if(rEl)rEl.textContent=rating||'--';

  /* Year - try labels first, then post date, then title */
  var wrap=document.getElementById('pdWrap');
  var yEl=document.getElementById('postYear');
  if(wrap&&yEl){
    var y='';
    /* Extract year from labels (e.g. '2024', 'Year-2024') */
    for(var i=0;i<labels.length;i++){
      var lb=labels[i].trim();
      var ym=lb.match(/^(\d{4})$/);
      if(!ym)ym=lb.match(/[Yy]ear[-:]?(\d{4})/);
      if(ym){y=ym[1];break;}
    }
    /* Fallback: post date */
    if(!y){
      var ds=wrap.querySelector('.post-date-data');
      y=extractYear(ds?ds.textContent.trim():'');
    }
    /* Fallback: extract from title like 'Inception (2010)' */
    if(!y){
      var tEl=document.getElementById('pdTitle');
      if(tEl){var tm=(tEl.textContent||'').match(/\((\d{4})\)/);if(tm)y=tm[1];}
    }
    if(y)yEl.textContent=y;
  }

  /* Duration */
  var duration='';
  for(var i=0;i<labels.length;i++){var d=getDuration(labels[i]);if(d){duration=d;break;}}
  if(!duration){
    var body=document.getElementById('pdBodyRaw');
    if(body){
      var txt=body.value||body.textContent||'';
      var dm=txt.match(/Duration[:\s]*(\d{1,2}:\d{2}(?::\d{2})?)/i);
      if(dm)duration=dm[1];
    }
  }
  var dEl=document.getElementById('postDuration');
  if(dEl&&duration)dEl.textContent=duration;

  /* Genre pills */
  var genres=[];
  for(var i=0;i<labels.length;i++){if(isGenre(labels[i]))genres.push(labels[i].trim());}
  var gc=document.getElementById('pdGenrePills');
  if(gc){
    var html='';
    for(var i=0;i<genres.length&&i<5;i++)html+='<span class="genre-pill">'+genres[i]+'</span>';
    gc.innerHTML=html;
  }

  /* Extract Cover & Poster URLs from post body */
  extractCoverPoster();

  /* Parse post body for tabs */
  parsePostBody();

  /* Remove pdBodyRaw from DOM to free memory */
  var rawBody=document.getElementById('pdBodyRaw');
  if(rawBody)rawBody.innerHTML='';

  /* Hide skeleton, show post content */
  var skel=document.getElementById('pdSkeleton');
  var pdW=document.getElementById('pdWrap');
  if(skel)skel.classList.add('hide');
  if(pdW)pdW.classList.add('show');
}

/* ===== POST DETAIL: Extract Cover & Poster URLs ===== */
function extractCoverPoster(){
  var bodyEl=document.getElementById('pdBodyRaw');
  if(!bodyEl)return;
  var bhtml=bodyEl.value||bodyEl.textContent||'';
  var coverUrl='',posterUrl='';
  /* Fast regex for Cover */
  var cMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Cover[\s]*<\/h[2-4]>\s*<img[^>]*src\s*=\s*["']([^"']+)["']/i);
  /* Also check for anchor-wrapped images: <h2>Poster</h2><a href="..."><img src="..."></a> */
  if(!cMatch)cMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Cover[\s]*<\/h[2-4]>\s*<a[^>]+><img[^>]*src\s*=\s*["']([^"']+)["']/i);
  if(!cMatch)cMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Cover[\s]*<\/h[2-4]>\s*<a[^>]*href\s*=\s*["']([^"']+)["']/i);
  if(!cMatch)cMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Cover[\s]*<\/h[2-4]>[\s\S]*?<img[^>]*src\s*=\s*["']([^"']+)["']/i);
  if(cMatch)coverUrl=cMatch[1];
  /* Fast regex for Poster */
  var pMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Poster[\s]*<\/h[2-4]>\s*<img[^>]*src\s*=\s*["']([^"']+)["']/i);
  if(!pMatch)pMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Poster[\s]*<\/h[2-4]>\s*<a[^>]+><img[^>]*src\s*=\s*["']([^"']+)["']/i);
  if(!pMatch)pMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Poster[\s]*<\/h[2-4]>\s*<a[^>]*href\s*=\s*["']([^"']+)["']/i);
  if(!pMatch)pMatch=bhtml.match(/<h[2-4][^>]*>[\s]*Poster[\s]*<\/h[2-4]>[\s\S]*?<img[^>]*src\s*=\s*["']([^"']+)["']/i);
  if(pMatch)posterUrl=pMatch[1];
  /* Fallback: img alt/class */
  if(!coverUrl||!posterUrl){
    var allImgSrcs=[];
    var imgRe=/<img[^>]*src\s*=\s*["']([^"']+)["'][^>]*(?:alt|class)\s*=\s*["']([^"']+)["']/gi;
    var m;while((m=imgRe.exec(bhtml))!==null){allImgSrcs.push({src:m[1],attr:m[2].toLowerCase()});}
    imgRe=/<img[^>]*(?:alt|class)\s*=\s*["']([^"']+)["'][^>]*src\s*=\s*["']([^"']+)["']/gi;
    while((m=imgRe.exec(bhtml))!==null){allImgSrcs.push({src:m[2],attr:m[1].toLowerCase()});}
    for(var j=0;j<allImgSrcs.length;j++){
      if(!coverUrl&&(/cover|banner/i.test(allImgSrcs[j].attr)))coverUrl=allImgSrcs[j].src;
      if(!posterUrl&&/poster/i.test(allImgSrcs[j].attr))posterUrl=allImgSrcs[j].src;
    }
  }
  /* Get featured image fallback URL */
  var featuredUrl='';
  var fiEl=document.getElementById('pdFeaturedImg');
  if(fiEl)featuredUrl=(fiEl.textContent||'').trim();

  /* Set cover image on hero */
  var heroImg=document.getElementById('pdHeroImg');
  if(heroImg){
    if(coverUrl){heroImg.src=coverUrl;}
    else if(featuredUrl){heroImg.src=featuredUrl;}
  }
  /* Set poster image on thumb */
  var posterImg=document.getElementById('pdPosterImg');
  if(posterImg){
    if(posterUrl){posterImg.src=posterUrl;}
    else if(featuredUrl){posterImg.src=featuredUrl;}
  }
}

/* ===== POST DETAIL: Parse Post Body ===== */
function parsePostBody(){
  var bodyEl=document.getElementById('pdBodyRaw');
  if(!bodyEl)return;
  var bodyHTML=bodyEl.value||bodyEl.textContent||'';
  var tmp=document.createElement('div');
  tmp.innerHTML=bodyHTML;

  /* Extract all text nodes and elements */
  var paragraphs=[];
  var tables=[];
  var headings=[];
  var allLinks=[];
  var allDivs=tmp.querySelectorAll('div, p, h1, h2, h3, h4, table, a, br, span');

  /* Collect paragraphs (non-empty text blocks before tables) */
  var children=tmp.children;
  var synopsisParts=[];
  var downloadSection=false;
  var techSection=false;
  var techTable=null;
  var serverSections=[];

  for(var i=0;i<children.length;i++){
    var el=children[i];
    var tag=el.tagName.toLowerCase();
    var text=(el.textContent||'').trim();

    /* Detect download section by heading text */
    if((tag==='h2'||tag==='h3'||tag==='h4')&&text){
      if(/download|server|link/i.test(text)){
        downloadSection=true;
        techSection=false;
        serverSections.push({name:text,items:[]});
        continue;
      }
      if(/info|detail|technical|spec/i.test(text)){
        techSection=true;
        downloadSection=false;
        continue;
      }
    }

    /* Collect synopsis paragraphs (before any download/info heading) */
    if(!downloadSection&&!techSection&&text.length>20&&!/^\d+$/.test(text)){
      if(tag==='p'||tag==='div'){
        synopsisParts.push(text);
      }
    }

    /* Collect tech info table */
    if(techSection&&tag==='table'){
      techTable=el;
    }

    /* Collect download links/tables */
    if(downloadSection){
      if(tag==='table'){
        var rows=el.querySelectorAll('tr');
        for(var r=0;r<rows.length;r++){
          var cells=rows[r].querySelectorAll('td, th');
          if(cells.length>=2){
            var qName=(cells[0].textContent||'').trim();
            var link=cells[1].querySelector('a');
            var href=link?link.getAttribute('href'):'';
            var linkText=(cells[1].textContent||'').trim();
            var format='';
            /* Try to extract format from second cell */
            var allText=cells[1].textContent||'';
            var fmtMatch=allText.match(/(MKV|MP4|AVI|WEB-DL|BluRay|HDRip|DVDRip)/i);
            if(fmtMatch)format=fmtMatch[1];
            var subtitleMatch=allText.match(/(Myanmar|English|Korean|Japanese|Chinese|Hardsub|Softsub)[\s]*(Subtitle)?/i);
            if(subtitleMatch)format+=(format?' \u00b7 ':'')+subtitleMatch[0];

            if(serverSections.length>0){
              serverSections[serverSections.length-1].items.push({
                quality:qName,
                format:format||linkText,
                link:href
              });
            }
          }
        }
      }
      /* Also check for standalone links */
      if(tag==='a'){
        var href=el.getAttribute('href');
        var linkText=(el.textContent||'').trim();
        if(href&&serverSections.length>0){
          serverSections[serverSections.length-1].items.push({
            quality:linkText,
            format:'',
            link:href
          });
        }
      }
    }

    /* Collect all links from any part */
    if(tag==='a'){
      allLinks.push({text:(el.textContent||'').trim(),href:el.getAttribute('href')||''});
    }
  }

  /* ===== RENDER DETAIL TAB ===== */
  var synEl=document.getElementById('pdSynopsisText');
  var viewMoreBtn=document.getElementById('pdViewMore');
  if(synEl){
    var synText=synopsisParts.length>0?synopsisParts.join(' '):'No synopsis available.';
    if(synText.length>200){
      synEl.textContent=synText.substring(0,200)+'...';
      synEl.dataset.full=synText;
      if(viewMoreBtn){
        viewMoreBtn.style.display='inline-flex';
        viewMoreBtn.addEventListener('click',function(){
          if(this.classList.contains('expanded')){
            synEl.textContent=synEl.dataset.full.substring(0,200)+'...';
            this.classList.remove('expanded');
            this.querySelector('span').textContent='View More';
            this.querySelector('i').className='fas fa-chevron-down';
          }else{
            synEl.textContent=synEl.dataset.full;
            this.classList.add('expanded');
            this.querySelector('span').textContent='View Less';
            this.querySelector('i').className='fas fa-chevron-up';
          }
        });
      }
    }else{
      synEl.textContent=synText;
    }
  }

  /* Render tech details */
  renderTechDetails(techTable, tmp);

  /* ===== RENDER DOWNLOAD TAB ===== */
  renderDownloadTab(serverSections, allLinks, tmp);

  /* Free tmp DOM memory */
  tmp.innerHTML='';
}

function renderTechDetails(table, body){
  var listEl=document.getElementById('pdTechList');
  if(!listEl)return;

  var techData={};
  /* Try extracting from table */
  if(table){
    var rows=table.querySelectorAll('tr');
    for(var i=0;i<rows.length;i++){
      var cells=rows[i].querySelectorAll('td, th');
      if(cells.length>=2){
        var key=(cells[0].textContent||'').trim();
        var val=(cells[1].textContent||'').trim();
        techData[key]=val;
      }
    }
  }

  /* Fallback: extract from post body text */
  if(Object.keys(techData).length===0){
    var text=(body?body.textContent:'')||'';
    var patterns=[
      {key:'Quality',regex:/Quality[:\s]*([^\n\r,]+)/i,icon:'fa-cog'},
      {key:'Format',regex:/Format[:\s]*([^\n\r,]+)/i,icon:'fa-file-video'},
      {key:'Genre',regex:/Genre[:\s]*([^\n\r,]+)/i,icon:'fa-masks-theater'},
      {key:'Duration',regex:/Duration[:\s]*(\d{1,2}:\d{2}(?::\d{2})?)/i,icon:'fa-clock'},
      {key:'Subtitle',regex:/(?:Sub[\s]*title|Language)[:\s]*([^\n\r,]+)/i,icon:'fa-closed-captioning'},
      {key:'Director',regex:/(?:Director|Directed[\s]*by)[:\s]*([^\n\r,]+)/i,icon:'fa-video'}
    ];
    for(var i=0;i<patterns.length;i++){
      var m=text.match(patterns[i].regex);
      if(m)techData[patterns[i].key]=m[1].trim();
    }
  }

  var iconMap={Quality:'fa-cog',Format:'fa-file-video',Genre:'fa-masks-theater',Duration:'fa-clock',Subtitle:'fa-closed-captioning',Director:'fa-video',Resolution:'fa-expand',Size:'fa-hard-drive',Release:'fa-calendar',Country:'fa-globe',Language:'fa-language'};
  var html='';
  var keys=['Quality','Format','Genre','Duration','Subtitle','Director','Resolution','Size','Release','Country','Language'];
  for(var i=0;i<keys.length;i++){
    var k=keys[i];
    if(techData[k]){
      var icon=iconMap[k]||'fa-circle-info';
      html+='<div class="pd-tech-item">';
      html+='<div class="pd-tech-icon"><i class="fas '+icon+'"></i></div>';
      html+='<div><div class="pd-tech-label">'+k+'</div><div class="pd-tech-value">'+techData[k]+'</div></div>';
      html+='</div>';
    }
  }
  if(!html)html='<div style="color:var(--muted);font-size:12px;text-align:center;padding:20px">No technical details found.</div>';
  listEl.innerHTML=html;
}

function renderDownloadTab(sections, allLinks, body){
  var listEl=document.getElementById('dlServerList');
  if(!listEl)return;

  /* If no structured sections found, try to extract from all links */
  if(sections.length===0){
    /* Look for download-related links in post body */
    var dlLinks=[];
    if(body){
      var links=body.querySelectorAll('a');
      for(var i=0;i<links.length;i++){
        var href=links[i].getAttribute('href')||'';
        var text=(links[i].textContent||'').trim();
        if(href&&(href.indexOf('http')===0||href.indexOf('/p/')===0||href.indexOf('drive.google')!==-1||href.indexOf('mega.nz')!==-1||href.indexOf('mediafire')!==-1)){
          dlLinks.push({text:text,href:href});
        }
      }
    }
    if(dlLinks.length>0){
      sections=[{name:'Server 1',items:[]}];
      for(var i=0;i<dlLinks.length;i++){
        sections[0].items.push({quality:'Download '+(i+1),format:dlLinks[i].text,link:dlLinks[i].href});
      }
    }
  }

  /* If still no sections, extract from tables in body */
  if(sections.length===0&&body){
    var tables=body.querySelectorAll('table');
    var serverCount=0;
    for(var t=0;t<tables.length;t++){
      var rows=tables[t].querySelectorAll('tr');
      var hasLinks=false;
      for(var r=0;r<rows.length;r++){
        if(rows[r].querySelector('a[href]')){hasLinks=true;break;}
      }
      if(hasLinks){
        serverCount++;
        var section={name:'Server '+serverCount,items:[]};
        for(var r=0;r<rows.length;r++){
          var cells=rows[r].querySelectorAll('td, th');
          if(cells.length>=2){
            var link=cells[1].querySelector('a');
            if(link){
              var qName=(cells[0].textContent||'').trim();
              var href=link.getAttribute('href');
              var allText=cells[1].textContent||'';
              section.items.push({quality:qName,format:allText.trim(),link:href});
            }
          }
        }
        if(section.items.length>0)sections.push(section);
      }
    }
  }

  /* Render server cards */
  var html='';
  if(sections.length===0){
    html='<div style="text-align:center;padding:30px;color:var(--muted);font-size:13px"><i class="fas fa-download" style="font-size:28px;display:block;margin-bottom:10px;color:var(--border)"></i>No download links found.</div>';
  }else{
    for(var s=0;s<sections.length;s++){
      var sec=sections[s];
      var qualityTags=[];
      for(var q=0;q<sec.items.length&&q<4;q++)qualityTags.push(sec.items[q].quality);
      html+='<div class="dl-server-card" data-server="'+s+'">';
      html+='<div class="dl-server-header" onclick="toggleServer(this)">';
      html+='<div class="dl-server-left">';
      html+='<div class="dl-server-icon"><i class="fas fa-server"></i></div>';
      html+='<div><div class="dl-server-name">'+sec.name+'</div>';
      html+='<div class="dl-server-qualities">';
      for(var q=0;q<qualityTags.length;q++)html+='<span class="dl-server-quality-tag">'+qualityTags[q]+'</span>';
      html+='</div></div></div>';
      html+='<i class="fas fa-chevron-down dl-server-arrow"></i>';
      html+='</div>';
      html+='<div class="dl-server-body">';
      for(var q=0;q<sec.items.length;q++){
        var item=sec.items[q];
        html+='<div class="dl-quality-card">';
        html+='<div class="dl-quality-top">';
        html+='<span class="dl-quality-badge">'+item.quality+'</span>';
        html+='<span class="dl-quality-label">'+item.quality+'</span>';
        html+='</div>';
        if(item.format)html+='<div class="dl-quality-info">'+item.format+'</div>';
        if(item.link){
          html+='<a href="'+item.link+'" target="_blank" rel="nofollow noopener" class="dl-download-btn">';
          html+='<i class="fas fa-download"></i> Download '+item.quality;
          html+='</a>';
        }else{
          html+='<button class="dl-download-btn" style="opacity:.5;cursor:not-allowed" disabled><i class="fas fa-download"></i> Unavailable</button>';
        }
        html+='</div>';
      }
      html+='</div></div>';
    }
  }
  listEl.innerHTML=html;
}

/* Toggle server card expand/collapse */
window.toggleServer=function(el){
  var card=el.parentElement;
  card.classList.toggle('expanded');
};

/* ===== POST DETAIL: Explore Tab (Related Posts) ===== */
var exploreLoaded=false;
function loadExplore(){
  var c=document.getElementById('exploreGrid');
  if(!c)return;
  var labels=(window._pl&&window._pl.length>0)?window._pl:[];
  if(labels.length===0){
    var wrap=document.getElementById('pdWrap');
    if(wrap){
      var spans=wrap.querySelectorAll('.label-data');
      for(var i=0;i<spans.length;i++){var v=spans[i].textContent.trim();if(v)labels.push(v);}
    }
  }
  var feedLabel='';
  for(var i=0;i<labels.length;i++){
    if(isGenre(labels[i])){feedLabel=labels[i];break;}
  }
  if(!feedLabel&&labels.length>0)feedLabel=labels[0];
  if(!feedLabel){
    c.innerHTML='<div style="flex:1;text-align:center;padding:30px;color:var(--muted);font-size:13px">No recommendations available.</div>';
    return;
  }
  c.innerHTML='<div style="flex:1;text-align:center;padding:30px;color:var(--muted);font-size:12px"><i class="fas fa-spinner fa-spin" style="font-size:20px;margin-bottom:8px;display:block"></i>Loading...</div>';
  var feedUrl=window.location.origin+'/feeds/posts/default/-/'+encodeURIComponent(feedLabel)+'?max-results=8&alt=json';
  var currentUrl=window.location.href.replace(/\/$/, '').replace(/\?m=1$/,'').replace(/\?m=0$/,'');
  fetch(feedUrl).then(function(r){return r.json();}).then(function(d){
    if(!d.feed||!d.feed.entry){
      c.innerHTML='<div style="flex:1;text-align:center;padding:20px;color:var(--muted);font-size:12px">No related posts found.</div>';
      return;
    }
    var h='';
    var count=0;
    d.feed.entry.forEach(function(e){
      if(count>=6)return;
      var t=e.title.$t,l='',img=PLACEHOLDER;
      e.link.forEach(function(k){if(k.rel==='alternate')l=k.href;});
      if(e.media$thumbnail)img=e.media$thumbnail.url.replace('/s72-c/','/w300-h450-c/');
      var postUrl=l.replace(/\/$/, '').replace(/\?m=1$/,'').replace(/\?m=0$/,'');
      if(l&&t&&postUrl!==currentUrl){
        var rating=getRating(null);
        if(e.category){for(var i=0;i<e.category.length;i++){var r=getRating(e.category[i].term);if(r){rating=r;break;}}}
        var year='';if(e.published)year=new Date(e.published.$t).getFullYear();
        var quality='HD';
        if(e.category){for(var i=0;i<e.category.length;i++){var lb=e.category[i].term||'';if(/4K|2160p/i.test(lb)){quality='4K';break;}if(/1080p/i.test(lb))quality='1080p';else if(/720p/i.test(lb))quality='720p';}}
        h+='<a href="'+l+'" class="explore-card">';
        h+='<div class="explore-poster">';
        h+='<img alt="'+t+'" data-src="'+img+'" onerror="this.src=\''+PLACEHOLDER+'\'" decoding="async"/>';
        h+='<span class="explore-qbadge">'+quality+'</span>';
        if(rating)h+='<span class="explore-rbadge"><i class="fas fa-star"></i> '+rating+'</span>';
        h+='</div>';
        h+='<div class="explore-info"><div class="explore-title">'+t+'</div>';
        if(year)h+='<div class="explore-year">'+year+'</div>';
        h+='</div></a>';
        count++;
      }
    });
    if(!h)h='<div style="flex:1;text-align:center;padding:20px;color:var(--muted);font-size:12px">No related posts found.</div>';
    c.innerHTML=h;
    /* Lazy load images */
    var expImgs=c.querySelectorAll('img[data-src]');
    if(expImgs.length>0&&'IntersectionObserver'in window){
      var eObs=new IntersectionObserver(function(entries){
        for(var ei=0;ei<entries.length;ei++){
          if(entries[ei].isIntersecting){var ei2=entries[ei].target;if(ei2.dataset.src){ei2.src=ei2.dataset.src;ei2.removeAttribute('data-src');}eObs.unobserve(ei2);}
        }
      },{rootMargin:'200px'});
      for(var ex=0;ex<expImgs.length;ex++)eObs.observe(expImgs[ex]);
    }else{
      for(var ef=0;ef<expImgs.length;ef++){if(expImgs[ef].dataset.src){expImgs[ef].src=expImgs[ef].dataset.src;}}
    }
  }).catch(function(){
    c.innerHTML='<div style="flex:1;text-align:center;padding:20px;color:var(--muted);font-size:12px">Failed to load recommendations.</div>';
  });
}

/* ===== Bottom Nav Active State ===== */
(function(){
  var url=window.location.href;
  var bns=document.querySelectorAll('.bn-item');
  for(var i=0;i<bns.length;i++){
    bns[i].classList.remove('active');
    var pg=bns[i].getAttribute('data-page');
    if(pg==='home'&&url.indexOf('/search/')===-1&&url.indexOf('/p/')===-1)bns[i].classList.add('active');
    if(url.indexOf('/search/label/Movie')!==-1&&pg==='movies')bns[i].classList.add('active');
    if(url.indexOf('/search/label/Series')!==-1&&pg==='series')bns[i].classList.add('active');
  }
})();

/* ===== Clean Blogger Defaults ===== */
function cleanBlogger(){
  var sels=['.status-msg-wrap','.blog-posts','.blog-pager','.feed-links','.blog-feeds'];
  for(var i=0;i<sels.length;i++){
    var els=document.querySelectorAll(sels[i]);
    for(var j=0;j<els.length;j++){try{els[j].style.display='none';}catch(e){}}
  }
}

/* ===== Init ===== */
function init(){
  injectCSS();
  cleanBlogger();
  buildHomepage();
  processPostDetail();
  initTabs();
  /* Bottom nav padding */
  if(window.innerWidth<=768)document.body.classList.add('bn-visible');
  window.addEventListener('resize',function(){
    if(window.innerWidth<=768)document.body.classList.add('bn-visible');
    else document.body.classList.remove('bn-visible');
  });
}

if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',init);
else init();

})();
